#define TAG "FIRMWARE_UPDATER"

// Function to download firmware binary from server
static esp_err_t http_download(const char *url, const char *filename) {
    esp_http_client_config_t config = {
        .url = url,
        .method = HTTP_METHOD_GET,
        .timeout_ms = 10000,
    };

    esp_http_client_handle_t client;
    esp_err_t ret = esp_http_client_init(&config, &client);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize http client");
        return ret;
    }

    ret = esp_http_client_perform(client);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to perform request");
        return ret;
    }

    int content_length = esp_http_client_get_content_length(client);
    char *buffer = malloc(content_length + 1);

    ret = esp_http_client_read(client, buffer, content_length);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read response");
        free(buffer);
        return ret;
    }

    // Save firmware binary to flash memory
    FILE *fp = fopen(filename, "wb");
    if (!fp) {
        ESP_LOGE(TAG, "Failed to open file for writing");
        free(buffer);
        return ESP_FAIL;
    }

    fwrite(buffer, 1, content_length, fp);
    fclose(fp);

    free(buffer);
    esp_http_client_close(client);
    return ESP_OK;
}

